class Solution:
    def getKth(self, lo: int, hi: int, k: int) -> int:
        powers = [self.power(x) for x in range(lo, hi + 1)]
        sorted_indices = sorted(range(len(powers)), key=lambda i: (powers[i], i))
        return sorted_indices[k - 1]

    def power(self, x: int) -> int:
        count = 0
        while x != 1:
            count += 1
            if x % 2 == 0:
                x //= 2
            else:
                x = 3 * x + 1
        return count
